namespace RecipeCommunity.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public int TotalRatings { get; set; }
    public int RatingCount { get; set; }

    public double AverageRating => RatingCount == 0 ? 0 : (double)TotalRatings / RatingCount;
}

using System.ComponentModel.DataAnnotations;

namespace RecipeCommunity.Models;

public class RecipeSubmission
{
    [Required(ErrorMessage = "Title is required.")]
    [StringLength(100, ErrorMessage = "Title must be 100 characters or fewer.")]
    public string Title { get; set; } = string.Empty;

    [Required(ErrorMessage = "Category is required.")]
    public string Category { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please add at least one ingredient.")]
    public string Ingredients { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please add at least one step.")]
    public string Steps { get; set; } = string.Empty;

    [StringLength(300, ErrorMessage = "Description must be 300 characters or fewer.")]
    public string Description { get; set; } = string.Empty;
}

using RecipeCommunity.Models;

namespace RecipeCommunity.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;
    private readonly Lock _lock = new();

    public RecipeService()
    {
        _recipes = CreateSeedData();
        _nextId = _recipes.Max(r => r.Id) + 1;
    }

    public List<string> GetCategories()
    {
        lock (_lock)
        {
            return _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();
        }
    }

    public List<Recipe> GetByCategory(string category)
    {
        lock (_lock)
        {
            return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
        }
    }

    public Recipe? GetById(int id)
    {
        lock (_lock)
        {
            return _recipes.FirstOrDefault(r => r.Id == id);
        }
    }

    public void AddRating(int recipeId, int stars)
    {
        if (stars < 1 || stars > 5) return;

        lock (_lock)
        {
            var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
            if (recipe is not null)
            {
                recipe.TotalRatings += stars;
                recipe.RatingCount++;
            }
        }
    }

    public Recipe AddRecipe(RecipeSubmission submission)
    {
        lock (_lock)
        {
            var recipe = new Recipe
            {
                Id = _nextId++,
                Title = submission.Title,
                Category = submission.Category,
                Description = submission.Description,
                Ingredients = submission.Ingredients
                    .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                    .ToList(),
                Steps = submission.Steps
                    .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                    .ToList()
            };
            _recipes.Add(recipe);
            return recipe;
        }
    }

    private static List<Recipe> CreateSeedData() =>
    [
        new()
        {
            Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
            Description = "A simple, classic pizza with fresh mozzarella and basil.",
            Ingredients = ["Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt"],
            Steps = ["Preheat oven to 475°F.", "Roll out dough on a floured surface.", "Spread crushed tomatoes over dough.", "Add torn mozzarella pieces.", "Bake for 10-12 minutes until crust is golden.", "Top with fresh basil and a drizzle of olive oil."],
            TotalRatings = 23, RatingCount = 5
        },
        new()
        {
            Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
            Description = "Creamy Roman pasta with eggs, cheese, and pancetta.",
            Ingredients = ["Spaghetti", "Pancetta", "Eggs", "Pecorino Romano", "Black pepper"],
            Steps = ["Cook spaghetti in salted water.", "Fry pancetta until crispy.", "Whisk eggs with grated pecorino and pepper.", "Toss hot pasta with pancetta.", "Remove from heat and stir in egg mixture.", "Serve immediately with extra cheese."],
            TotalRatings = 18, RatingCount = 4
        },
        new()
        {
            Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
            Description = "Tender chicken pieces in a rich, spiced tomato sauce.",
            Ingredients = ["Chicken breast", "Yogurt", "Garam masala", "Tomato sauce", "Heavy cream", "Onion", "Garlic", "Ginger"],
            Steps = ["Marinate chicken in yogurt and spices for 1 hour.", "Grill or pan-fry chicken until charred.", "Sauté onion, garlic, and ginger.", "Add tomato sauce and simmer.", "Stir in cream and cooked chicken.", "Simmer 15 minutes and serve with rice."],
            TotalRatings = 20, RatingCount = 4
        },
        new()
        {
            Id = 4, Title = "Vegetable Pad Thai", Category = "Thai",
            Description = "Sweet, sour, and savory stir-fried rice noodles.",
            Ingredients = ["Rice noodles", "Tofu", "Bean sprouts", "Peanuts", "Lime", "Tamarind paste", "Fish sauce", "Sugar", "Eggs"],
            Steps = ["Soak rice noodles in warm water.", "Press and cube tofu, then pan-fry.", "Scramble eggs in the same pan.", "Add noodles and sauce (tamarind, fish sauce, sugar).", "Toss with bean sprouts.", "Serve with crushed peanuts and lime."],
            TotalRatings = 14, RatingCount = 3
        },
        new()
        {
            Id = 5, Title = "Beef Tacos", Category = "Mexican",
            Description = "Seasoned ground beef in warm tortillas with fresh toppings.",
            Ingredients = ["Ground beef", "Taco seasoning", "Corn tortillas", "Lettuce", "Tomato", "Cheddar cheese", "Sour cream", "Salsa"],
            Steps = ["Brown ground beef and drain fat.", "Add taco seasoning with water and simmer.", "Warm tortillas in a dry skillet.", "Assemble tacos with beef and toppings.", "Serve with salsa and sour cream."],
            TotalRatings = 16, RatingCount = 4
        },
        new()
        {
            Id = 6, Title = "Chocolate Lava Cake", Category = "Desserts",
            Description = "Rich individual chocolate cakes with a molten center.",
            Ingredients = ["Dark chocolate", "Butter", "Eggs", "Sugar", "Flour", "Vanilla extract"],
            Steps = ["Preheat oven to 425°F and grease ramekins.", "Melt chocolate and butter together.", "Whisk in eggs, sugar, and vanilla.", "Fold in flour gently.", "Pour into ramekins and bake 12-14 minutes.", "Invert onto plates and serve immediately."],
            TotalRatings = 25, RatingCount = 5
        },
        new()
        {
            Id = 7, Title = "Green Curry", Category = "Thai",
            Description = "Aromatic coconut curry with vegetables and Thai basil.",
            Ingredients = ["Green curry paste", "Coconut milk", "Chicken or tofu", "Bamboo shoots", "Thai basil", "Fish sauce", "Sugar"],
            Steps = ["Fry curry paste in a splash of coconut cream.", "Add protein and cook through.", "Pour in coconut milk and bring to a simmer.", "Add bamboo shoots, fish sauce, and sugar.", "Cook 10 minutes until flavors meld.", "Finish with Thai basil and serve over rice."],
            TotalRatings = 12, RatingCount = 3
        },
        new()
        {
            Id = 8, Title = "Guacamole", Category = "Mexican",
            Description = "Fresh avocado dip with lime and cilantro.",
            Ingredients = ["Avocados", "Lime juice", "Cilantro", "Red onion", "Jalapeño", "Salt", "Tomato"],
            Steps = ["Halve and pit avocados.", "Mash to desired consistency.", "Stir in lime juice, onion, jalapeño, and cilantro.", "Fold in diced tomato.", "Season with salt and serve with chips."],
            TotalRatings = 9, RatingCount = 2
        },
    ];
}

