@page "/category/{CategoryName}"
@using RecipeCommunity.Services
@using RecipeCommunity.Models

@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes</PageTitle>

<h1>@CategoryName Recipes</h1>

@if (recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category.</div>
}
else
{
    <div class="row">
        @foreach (var recipe in recipes)
        {
            <div class="col-md-6 mb-4">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h4 class="card-title">@recipe.Title</h4>
                        <p class="card-text">@recipe.Description</p>
                        <p class="text-muted mb-2">
                            @if (recipe.RatingCount > 0)
                            {
                                <span>⭐ @recipe.AverageRating.ToString("0.0") (@recipe.RatingCount ratings)</span>
                            }
                            else
                            {
                                <span>No ratings yet</span>
                            }
                        </p>
                        <a href="recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

<a href="/" class="btn btn-outline-secondary mt-2">← Back to Home</a>

@code {
    [Parameter]
    public string CategoryName { get; set; } = string.Empty;

    private List<Recipe> recipes = [];

    protected override void OnInitialized()
    {
        recipes = RecipeService.GetByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@using RecipeCommunity.Services
@using RecipeCommunity.Models

@inject RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe")</PageTitle>

@if (recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
    <a href="/" class="btn btn-outline-secondary">← Back to Home</a>
}
else
{
    <h1>@recipe.Title</h1>
    <p class="lead">@recipe.Description</p>
    <span class="badge bg-secondary mb-3">@recipe.Category</span>

    <StarRating RecipeId="recipe.Id" @rendermode="InteractiveServer" />

    <div class="row mt-4">
        <div class="col-md-5">
            <h4>🥘 Ingredients</h4>
            <ul class="list-group list-group-flush">
                @foreach (var ingredient in recipe.Ingredients)
                {
                    <li class="list-group-item">@ingredient</li>
                }
            </ul>
        </div>
        <div class="col-md-7">
            <h4>📋 Steps</h4>
            <ol class="list-group list-group-numbered list-group-flush">
                @foreach (var step in recipe.Steps)
                {
                    <li class="list-group-item">@step</li>
                }
            </ol>
        </div>
    </div>

    <a href="category/@recipe.Category" class="btn btn-outline-secondary mt-4">← Back to @recipe.Category</a>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Recipe? recipe;

    protected override void OnInitialized()
    {
        recipe = RecipeService.GetById(Id);
    }
}

@using RecipeCommunity.Services
@inject RecipeService RecipeService

<div class="my-3">
    <span class="me-2">Rate this recipe:</span>
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <button class="btn btn-link p-0 fs-4 text-decoration-none"
                @onclick="() => SubmitRating(star)"
                disabled="@hasRated"
                title="@star star(s)">
            @(star <= displayStars ? "★" : "☆")
        </button>
    }

    @if (hasRated)
    {
        <span class="ms-2 text-success">✓ Thanks for rating!</span>
    }

    @if (averageRating > 0)
    {
        <span class="ms-3 text-muted">Avg: @averageRating.ToString("0.0") (@ratingCount)</span>
    }
</div>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private int displayStars;
    private bool hasRated;
    private double averageRating;
    private int ratingCount;

    protected override void OnInitialized()
    {
        LoadRating();
    }

    private void SubmitRating(int stars)
    {
        if (hasRated) return;
        RecipeService.AddRating(RecipeId, stars);
        displayStars = stars;
        hasRated = true;
        LoadRating();
    }

    private void LoadRating()
    {
        var recipe = RecipeService.GetById(RecipeId);
        if (recipe is not null)
        {
            averageRating = recipe.AverageRating;
            ratingCount = recipe.RatingCount;
        }
    }
}

@page "/submit"
@using RecipeCommunity.Models
@using RecipeCommunity.Services
@rendermode InteractiveServer

@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe</PageTitle>

<h1>📝 Submit a Recipe</h1>
<p>Share your favorite recipe with the community.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Recipe submitted!</h4>
        <p>Your recipe "<strong>@submission.Title</strong>" has been added.</p>
        <a href="recipe/@newRecipeId" class="btn btn-primary me-2">View Recipe</a>
        <a href="submit" class="btn btn-outline-secondary" @onclick="Reset">Submit Another</a>
    </div>
}
else
{
    <EditForm Model="submission" OnValidSubmit="HandleSubmit" FormName="submitRecipe" class="mt-3">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" @bind-Value="submission.Title" class="form-control" placeholder="e.g. Grandma's Apple Pie" />
            <ValidationMessage For="() => submission.Title" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" @bind-Value="submission.Category" class="form-select">
                <option value="">-- Select a category --</option>
                <option value="Italian">Italian</option>
                <option value="Indian">Indian</option>
                <option value="Thai">Thai</option>
                <option value="Mexican">Mexican</option>
                <option value="Desserts">Desserts</option>
                <option value="Other">Other</option>
            </InputSelect>
            <ValidationMessage For="() => submission.Category" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="description" class="form-label">Short Description</label>
            <InputText id="description" @bind-Value="submission.Description" class="form-control" placeholder="A brief summary of your recipe" />
            <ValidationMessage For="() => submission.Description" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" @bind-Value="submission.Ingredients" class="form-control" rows="5" placeholder="2 cups flour&#10;1 cup sugar&#10;3 eggs" />
            <ValidationMessage For="() => submission.Ingredients" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" @bind-Value="submission.Steps" class="form-control" rows="5" placeholder="Preheat oven to 350°F&#10;Mix dry ingredients&#10;Bake for 30 minutes" />
            <ValidationMessage For="() => submission.Steps" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-success">Submit Recipe</button>
        <a href="/" class="btn btn-outline-secondary ms-2">Cancel</a>
    </EditForm>
}

@code {
    private RecipeSubmission submission = new();
    private bool submitted;
    private int newRecipeId;

    private void HandleSubmit()
    {
        var recipe = RecipeService.AddRecipe(submission);
        newRecipeId = recipe.Id;
        submitted = true;
    }

    private void Reset()
    {
        submission = new();
        submitted = false;
    }
}

