@page "/category/{CategoryName}"
@using RecipeCommunity.Services
@using RecipeCommunity.Models

@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes</PageTitle>

<h1>@CategoryName Recipes</h1>

@if (recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category.</div>
}
else
{
    <div class="row">
        @foreach (var recipe in recipes)
        {
            <div class="col-md-6 mb-4">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h4 class="card-title">@recipe.Title</h4>
                        <p class="card-text">@recipe.Description</p>
                        <p class="text-muted mb-2">
                            @if (recipe.RatingCount > 0)
                            {
                                <span>⭐ @recipe.AverageRating.ToString("0.0") (@recipe.RatingCount ratings)</span>
                            }
                            else
                            {
                                <span>No ratings yet</span>
                            }
                        </p>
                        <a href="recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

<a href="/" class="btn btn-outline-secondary mt-2">← Back to Home</a>

@code {
    [Parameter]
    public string CategoryName { get; set; } = string.Empty;

    private List<Recipe> recipes = [];

    protected override void OnInitialized()
    {
        recipes = RecipeService.GetByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@using RecipeCommunity.Services
@using RecipeCommunity.Models

@inject RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe")</PageTitle>

@if (recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
    <a href="/" class="btn btn-outline-secondary">← Back to Home</a>
}
else
{
    <h1>@recipe.Title</h1>
    <p class="lead">@recipe.Description</p>
    <span class="badge bg-secondary mb-3">@recipe.Category</span>

    <StarRating RecipeId="recipe.Id" @rendermode="InteractiveServer" />

    <div class="row mt-4">
        <div class="col-md-5">
            <h4>🥘 Ingredients</h4>
            <ul class="list-group list-group-flush">
                @foreach (var ingredient in recipe.Ingredients)
                {
                    <li class="list-group-item">@ingredient</li>
                }
            </ul>
        </div>
        <div class="col-md-7">
            <h4>📋 Steps</h4>
            <ol class="list-group list-group-numbered list-group-flush">
                @foreach (var step in recipe.Steps)
                {
                    <li class="list-group-item">@step</li>
                }
            </ol>
        </div>
    </div>

    <a href="category/@recipe.Category" class="btn btn-outline-secondary mt-4">← Back to @recipe.Category</a>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Recipe? recipe;

    protected override void OnInitialized()
    {
        recipe = RecipeService.GetById(Id);
    }
}

